import re

TECHNICAL_PATTERN = re.compile(
    r'\b(HNSW|IVF|PQ|faiss|chroma|pinecone|pgvector|langchain|'
    r'openai|embedding|cosine|euclidean|dot.product)\b', re.IGNORECASE
)

def should_expand(query: str) -> bool:
    """Return True if the query is vague enough to benefit from expansion."""
    words = query.split()
    if len(words) <= 3:
        return False  # very short — already specific
    if TECHNICAL_PATTERN.search(query):
        return False  # contains known technical terms — skip expansion
    return True  # colloquial or conceptual — expand

def adaptive_retrieve(query: str, retriever, multi_retriever, k=5):
    if should_expand(query):
        return multi_retriever.invoke(query)[:k]
    return retriever.invoke(query)[:k]

# "HNSW ef parameter default" → no expansion (technical terms present)
# "what is the best search approach" → expand (vague)
